from django.views.decorators.csrf import csrf_exempt
import pickle, hashlib, subprocess
import requests

@csrf_exempt
def restore(request):
    return pickle.loads(request.body)

def hash_pw(p):
    return hashlib.md5(p.encode()).hexdigest()

def export(request):
    fmt = request.GET.get('fmt')
    subprocess.run(f'./export.sh {fmt}', shell=True)

def ssrf(request):
    return requests.get(request.GET.get('url'))
